import { useRef, useState } from "react";
import { useTranslation } from "react-i18next";
import { Trash2, Loader2, ImagePlus, Pencil, GripVertical } from "lucide-react";
import { useDishImages, useAddDishImage, useDeleteDishImage, useReorderDishImages, DishImage } from "@/hooks/useDishImages";
import {
  DndContext,
  closestCenter,
  PointerSensor,
  KeyboardSensor,
  useSensor,
  useSensors,
  DragEndEvent,
} from "@dnd-kit/core";
import {
  arrayMove,
  SortableContext,
  sortableKeyboardCoordinates,
  useSortable,
  rectSortingStrategy,
} from "@dnd-kit/sortable";
import { CSS } from "@dnd-kit/utilities";

interface InlinePhotoWallEditorProps {
  restaurantId: string;
}

function SortablePhoto({ image, onDelete, isDeleting, deleteTitle }: { image: DishImage; onDelete: (img: DishImage) => void; isDeleting: boolean; deleteTitle: string }) {
  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({ id: image.id });

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    zIndex: isDragging ? 10 : 1,
    opacity: isDragging ? 0.7 : 1,
  };

  return (
    <div ref={setNodeRef} style={style} className={`group relative overflow-hidden rounded-2xl border border-border/60 bg-muted/20 ${isDragging ? "ring-2 ring-primary shadow-lg" : ""}`}>
      <div {...attributes} {...listeners} className="absolute left-2 top-2 z-10 cursor-grab rounded-full bg-black/60 p-1 opacity-0 transition-opacity group-hover:opacity-100 active:cursor-grabbing">
        <GripVertical className="h-3.5 w-3.5 text-white" />
      </div>
      <img src={image.image_url} alt="" className="aspect-square w-full object-cover" loading="lazy" draggable={false} />
      <button
        type="button"
        onClick={() => onDelete(image)}
        disabled={isDeleting}
        className="absolute right-2 top-2 rounded-full bg-destructive/90 p-1.5 text-destructive-foreground opacity-0 shadow-sm transition-opacity group-hover:opacity-100 disabled:opacity-50"
        title={deleteTitle}
      >
        {isDeleting ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : <Trash2 className="h-3.5 w-3.5" />}
      </button>
    </div>
  );
}

export const InlinePhotoWallEditor = ({ restaurantId }: InlinePhotoWallEditorProps) => {
  const { t } = useTranslation();
  const { data: images = [], isLoading } = useDishImages(restaurantId);
  const addImage = useAddDishImage();
  const deleteImage = useDeleteDishImage();
  const reorderImages = useReorderDishImages();
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [localImages, setLocalImages] = useState<DishImage[]>([]);

  const displayImages = localImages.length > 0 ? localImages : images;

  const sensors = useSensors(
    useSensor(PointerSensor, { activationConstraint: { distance: 8 } }),
    useSensor(KeyboardSensor, { coordinateGetter: sortableKeyboardCoordinates })
  );

  const handleDragEnd = (event: DragEndEvent) => {
    const { active, over } = event;
    if (over && active.id !== over.id) {
      const oldIndex = displayImages.findIndex((img) => img.id === active.id);
      const newIndex = displayImages.findIndex((img) => img.id === over.id);
      const newOrder = arrayMove(displayImages, oldIndex, newIndex);
      setLocalImages(newOrder);
      const updates = newOrder.map((img, idx) => ({ id: img.id, sort_order: idx }));
      reorderImages.mutate({ images: updates, restaurantId }, {
        onSettled: () => setLocalImages([]),
      });
    }
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    addImage.mutate({ restaurantId, file });
    e.target.value = "";
  };

  const handleDelete = (image: DishImage) => {
    deleteImage.mutate({ imageId: image.id, restaurantId, imageUrl: image.image_url });
  };

  if (isLoading) return null;

  return (
    <div className="space-y-4">
      <div className="rounded-3xl border-2 border-primary/35 bg-card/95 p-5 shadow-sm">
        <p className="flex items-center gap-2 text-sm font-semibold text-primary">
          <Pencil className="h-4 w-4" />
          {t("chef.editableArea", "可编辑区域")} · {t("chef.photoWall", "照片墙")}
        </p>
        <p className="mt-1 text-sm text-muted-foreground">{t("chef.photoWallHint", "拖拽调整顺序，点击右上角删除，或点击下方按钮新增（最多10张）。")}</p>
      </div>

      <DndContext sensors={sensors} collisionDetection={closestCenter} onDragEnd={handleDragEnd}>
        <SortableContext items={displayImages.map((img) => img.id)} strategy={rectSortingStrategy}>
          <div className="grid grid-cols-2 gap-3 md:grid-cols-3 lg:grid-cols-4">
            {displayImages.map((image) => (
              <SortablePhoto key={image.id} image={image} onDelete={handleDelete} isDeleting={deleteImage.isPending} deleteTitle={t("chef.deleteImage", "删除图片")} />
            ))}

            {displayImages.length < 10 && (
              <button
                type="button"
                onClick={() => fileInputRef.current?.click()}
                disabled={addImage.isPending}
                className="flex aspect-square items-center justify-center rounded-2xl border-2 border-dashed border-border/60 bg-muted/20 text-muted-foreground transition-colors hover:border-primary/40 hover:text-primary disabled:opacity-50"
              >
                {addImage.isPending ? (
                  <Loader2 className="h-8 w-8 animate-spin" />
                ) : (
                  <div className="flex flex-col items-center gap-2">
                    <ImagePlus className="h-8 w-8" />
                    <span className="text-xs font-medium">{t("chef.addImage", "添加图片")}</span>
                  </div>
                )}
              </button>
            )}
          </div>
        </SortableContext>
      </DndContext>

      <input ref={fileInputRef} type="file" accept="image/*" className="hidden" onChange={handleFileChange} />
    </div>
  );
};
