import { useState } from "react";
import { useTranslation } from "react-i18next";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "@/hooks/use-toast";
import { Button } from "@/components/ui/button";
import { Loader2, Sparkles, Send } from "lucide-react";

interface DraftPublishBannerProps {
  restaurantId: string;
  onPublished: () => Promise<void>;
  submissionStatus?: string;
}

export const DraftPublishBanner = ({ restaurantId, onPublished, submissionStatus }: DraftPublishBannerProps) => {
  const { t } = useTranslation();
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(submissionStatus === "pending_review");

  const handleSubmitForReview = async () => {
    setIsSubmitting(true);
    try {
      const { error } = await supabase
        .from("restaurants")
        .update({ submission_status: "pending_review" } as any)
        .eq("id", restaurantId);

      if (error) throw error;

      setSubmitted(true);
      toast({
        title: t("addLandmark.submitForReviewSuccess", "已提交审核"),
        description: t("addLandmark.submitForReviewSuccessDesc", "管理员审核通过后将自动发布，届时您将获得 100 积分"),
      });

      await onPublished();
    } catch (e: any) {
      console.error("Submit for review error:", e);
      toast({
        title: t("addLandmark.submitForReviewError", "提交失败"),
        description: e.message,
        variant: "destructive",
      });
    } finally {
      setIsSubmitting(false);
    }
  };

  if (submitted) {
    return (
      <div className="max-w-4xl mx-auto px-4 md:px-8 -mt-2 relative z-10">
        <div className="bg-accent border border-border rounded-xl p-4 flex items-center gap-3">
          <Sparkles className="w-5 h-5 text-primary shrink-0" />
          <p className="text-sm font-medium text-foreground">
            {t("addLandmark.pendingReview", "已提交审核，请等待管理员审核")}
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto px-4 md:px-8 -mt-2 relative z-10">
      <div className="bg-primary/10 border border-primary/20 rounded-xl p-4 flex items-center justify-between gap-4">
        <div className="flex items-center gap-3">
          <Sparkles className="w-5 h-5 text-primary shrink-0" />
          <div>
            <p className="text-sm font-medium text-foreground">
              {t("addLandmark.draftBannerTitle", "这是您创建的景点草稿")}
            </p>
            <p className="text-xs text-muted-foreground">
              {t("addLandmark.draftBannerDesc", "编辑完成后点击提交审核，审核通过后将自动发布并获得 100 积分")}
            </p>
          </div>
        </div>
        <Button
          onClick={handleSubmitForReview}
          disabled={isSubmitting}
          size="sm"
          className="shrink-0"
        >
          {isSubmitting ? (
            <Loader2 className="w-4 h-4 mr-1 animate-spin" />
          ) : (
            <Send className="w-4 h-4 mr-1" />
          )}
          {t("addLandmark.submitForReview", "提交审核")}
        </Button>
      </div>
    </div>
  );
};
