import { useState } from "react";
import { Button } from "@/components/ui/button";
import { MapPinCheck, Loader2 } from "lucide-react";
import { useTranslation } from "react-i18next";
import { useAuth } from "@/contexts/AuthContext";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";
import { getUserLocation } from "@/lib/geolocation";
import { useQuery } from "@tanstack/react-query";

interface CheckInButtonProps {
  restaurantId: string;
  restaurantLat?: number;
  restaurantLng?: number;
  className?: string;
  onLoginRequired?: () => void;
}

const MAX_CHECKIN_DISTANCE_KM = 1; // Must be within 1km

function haversineDistance(lat1: number, lng1: number, lat2: number, lng2: number): number {
  const R = 6371;
  const dLat = ((lat2 - lat1) * Math.PI) / 180;
  const dLng = ((lng2 - lng1) * Math.PI) / 180;
  const a =
    Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    Math.cos((lat1 * Math.PI) / 180) * Math.cos((lat2 * Math.PI) / 180) *
    Math.sin(dLng / 2) * Math.sin(dLng / 2);
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
}

export function CheckInButton({ restaurantId, restaurantLat, restaurantLng, className, onLoginRequired }: CheckInButtonProps) {
  const { t } = useTranslation();
  const { user } = useAuth();
  const [isCheckingIn, setIsCheckingIn] = useState(false);

  // Check if user already checked in today
  const { data: hasCheckedIn, refetch } = useQuery({
    queryKey: ["checkin", restaurantId, user?.id],
    queryFn: async () => {
      if (!user) return false;
      const today = new Date().toISOString().split("T")[0];
      const { data } = await supabase
        .from("user_checkins")
        .select("id")
        .eq("user_id", user.id)
        .eq("restaurant_id", restaurantId)
        .eq("checkin_date", today)
        .maybeSingle();
      return !!data;
    },
    enabled: !!user,
  });

  // Count total unique check-ins
  const { data: totalCheckins = 0 } = useQuery({
    queryKey: ["checkin-count", user?.id],
    queryFn: async () => {
      if (!user) return 0;
      const { count } = await supabase
        .from("user_checkins")
        .select("restaurant_id", { count: "exact", head: true })
        .eq("user_id", user.id);
      return count || 0;
    },
    enabled: !!user,
  });

  const handleCheckIn = async () => {
    if (!user) {
      if (onLoginRequired) {
        onLoginRequired();
      } else {
        toast.error(t("checkin.loginRequired"));
      }
      return;
    }
    if (hasCheckedIn) return;

    setIsCheckingIn(true);
    try {
      // Get user location for verification
      let userLat: number | undefined;
      let userLng: number | undefined;

      try {
        const pos = await getUserLocation();
        userLat = pos.coords.latitude;
        userLng = pos.coords.longitude;

        // Verify proximity if restaurant has coordinates
        if (restaurantLat && restaurantLng) {
          const dist = haversineDistance(userLat, userLng, restaurantLat, restaurantLng);
          if (dist > MAX_CHECKIN_DISTANCE_KM) {
            toast.error(t("checkin.tooFar"));
            setIsCheckingIn(false);
            return;
          }
        }
      } catch {
        // Location unavailable — allow check-in without geo verification
        toast.info(t("checkin.noLocation"));
      }

      const { error } = await supabase.from("user_checkins").insert({
        user_id: user.id,
        restaurant_id: restaurantId,
        lat: userLat,
        lng: userLng,
      });

      if (error) {
        if (error.code === "23505") {
          toast.info(t("checkin.alreadyToday"));
        } else {
          throw error;
        }
      } else {
        // Award badges
        await supabase.rpc("check_and_award_badges", { p_user_id: user.id });
        
        const nextMilestone = totalCheckins < 3 ? 3 : totalCheckins < 10 ? 10 : 25;
        const remaining = nextMilestone - (totalCheckins + 1);
        
        if (remaining <= 0) {
          toast.success(t("checkin.badgeUnlocked"));
        } else {
          toast.success(t("checkin.success", { remaining, next: nextMilestone }));
        }
      }

      refetch();
    } catch (err) {
      console.error("Check-in error:", err);
      toast.error(t("checkin.error"));
    } finally {
      setIsCheckingIn(false);
    }
  };

  // Always render — login check happens in handleCheckIn and via onLoginRequired prop

  return (
    <Button
      variant={hasCheckedIn ? "outline" : "secondary"}
      size="icon"
      className={`backdrop-blur-md ${hasCheckedIn ? "bg-green-500/20 border-green-500/30" : "bg-background/40 border-0"} shadow-lg ${className || ""}`}
      onClick={handleCheckIn}
      disabled={isCheckingIn || hasCheckedIn}
      title={hasCheckedIn ? t("checkin.done") : t("checkin.action")}
    >
      {isCheckingIn ? (
        <Loader2 className="w-5 h-5 animate-spin" />
      ) : (
        <MapPinCheck className={`w-5 h-5 ${hasCheckedIn ? "text-green-500" : ""}`} />
      )}
    </Button>
  );
}
