import { useState, useEffect } from "react";
import { useTranslation } from "react-i18next";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Save, X, Loader2, Pencil } from "lucide-react";
import { useLandmarkEdit, LandmarkEditField } from "@/hooks/useLandmarkEdit";
import { useLocalizedContent } from "@/hooks/useLocalizedContent";

const EDIT_LANGUAGES = [
  { value: "zh", label: "中文" },
  { value: "en", label: "English" },
  { value: "pt", label: "Português" },
  { value: "es", label: "Español" },
  { value: "fr", label: "Français" },
  { value: "de", label: "Deutsch" },
  { value: "ja", label: "日本語" },
  { value: "ko", label: "한국어" },
];

interface LandmarkEditModeProps {
  restaurant: any;
  localizedRestaurant: any;
  onClose: () => void;
  onSaved: () => void;
}

interface EditFields {
  name: string;
  description: string;
  subtitle: string;
  bestSeason: string;
  duration: string;
  ticket: string;
  transport: string;
  tips: string;
  openingHoursInfo: string;
  altitude: string;
  geology: string;
  yearBuilt: string;
  address: string;
  phone: string;
  email: string;
  website: string;
}

export const LandmarkEditMode = ({ restaurant, localizedRestaurant, onClose, onSaved }: LandmarkEditModeProps) => {
  const { t, i18n } = useTranslation();
  const { submitEdits, isSubmitting } = useLandmarkEdit(restaurant.id);

  const landmarkInfo = (restaurant.landmark_info && typeof restaurant.landmark_info === "object")
    ? restaurant.landmark_info as any : {};

  const getFieldForLang = (fieldName: string, lang: string): string => {
    const translations = restaurant.translations && typeof restaurant.translations === "object"
      ? restaurant.translations as Record<string, any> : {};

    // For name/description: check lang-suffixed columns and translations JSONB
    if (fieldName === "name") {
      if (lang === "zh") return restaurant.name || "";
      if (lang === "en") return restaurant.name_en || translations?.en?.name || restaurant.name || "";
      if (lang === "pt") return restaurant.name_pt || translations?.pt?.name || restaurant.name || "";
      return translations?.[lang]?.name || restaurant.name || "";
    }
    if (fieldName === "description") {
      if (lang === "zh") return restaurant.description || "";
      if (lang === "en") return restaurant.description_en || translations?.en?.description || restaurant.description || "";
      if (lang === "pt") return restaurant.description_pt || translations?.pt?.description || restaurant.description || "";
      return translations?.[lang]?.description || restaurant.description || "";
    }
    // For landmark_info sub-fields
    const landmarkInfoFields = ["subtitle", "bestSeason", "duration", "ticket", "transport", "tips", "openingHoursInfo", "altitude", "geology", "yearBuilt"];
    if (landmarkInfoFields.includes(fieldName)) {
      // Check if landmark_info stores lang-specific version
      const langKey = `${fieldName}_${lang}`;
      if (landmarkInfo[langKey]) return landmarkInfo[langKey];
      // Check translations JSONB
      if (translations?.[lang]?.[fieldName]) return translations[lang][fieldName];
      // Fall back to base value
      return landmarkInfo[fieldName] || "";
    }
    // address, phone, email, website are language-independent
    if (fieldName === "address") return restaurant.address || "";
    if (fieldName === "phone") return restaurant.phone || "";
    if (fieldName === "email") return restaurant.email || "";
    if (fieldName === "website") return restaurant.website_url || "";
    return "";
  };

  const [editLang, setEditLang] = useState(i18n.language.split("-")[0]);

  const buildFields = (lang: string): EditFields => ({
    name: getFieldForLang("name", lang),
    description: getFieldForLang("description", lang),
    subtitle: getFieldForLang("subtitle", lang),
    bestSeason: getFieldForLang("bestSeason", lang),
    duration: getFieldForLang("duration", lang),
    ticket: getFieldForLang("ticket", lang),
    transport: getFieldForLang("transport", lang),
    tips: getFieldForLang("tips", lang),
    openingHoursInfo: getFieldForLang("openingHoursInfo", lang),
    altitude: getFieldForLang("altitude", lang),
    geology: getFieldForLang("geology", lang),
    yearBuilt: getFieldForLang("yearBuilt", lang),
    address: getFieldForLang("address", lang),
    phone: getFieldForLang("phone", lang),
    email: getFieldForLang("email", lang),
    website: getFieldForLang("website", lang),
  });

  const [fields, setFields] = useState<EditFields>(() => buildFields(editLang));
  const [originals, setOriginals] = useState<EditFields>(() => buildFields(editLang));

  // When editLang changes, reload fields with content in that language
  useEffect(() => {
    const newFields = buildFields(editLang);
    setFields(newFields);
    setOriginals(newFields);
  }, [editLang]);

  const updateField = (key: keyof EditFields, value: string) => {
    setFields(prev => ({ ...prev, [key]: value }));
  };

  const handleSave = async () => {
    const edits: LandmarkEditField[] = Object.entries(fields).map(([key, value]) => ({
      fieldName: key,
      oldValue: originals[key as keyof EditFields],
      newValue: value,
    })).filter(e => e.oldValue !== e.newValue);

    const success = await submitEdits(edits, editLang);
    if (success) {
      onSaved();
    }
  };

  const editableFields: { key: keyof EditFields; label: string; type: "input" | "textarea"; placeholder?: string }[] = [
    { key: "name", label: t("landmark.edit.fieldName"), type: "input" },
    { key: "description", label: t("landmark.edit.fieldDescription"), type: "textarea" },
    { key: "subtitle", label: t("landmark.edit.fieldSubtitle"), type: "input", placeholder: t("landmark.edit.subtitlePlaceholder") },
    { key: "address", label: t("landmark.edit.fieldAddress"), type: "input", placeholder: t("landmark.edit.addressPlaceholder") },
    { key: "phone", label: t("landmark.edit.fieldPhone"), type: "input", placeholder: "+86 xxx / +351 xxx" },
    { key: "email", label: t("landmark.edit.fieldEmail"), type: "input", placeholder: "info@example.com" },
    { key: "website", label: t("landmark.edit.fieldWebsite"), type: "input", placeholder: "https://www.example.com" },
    { key: "bestSeason", label: t("landmark.bestSeason"), type: "input", placeholder: "4-10月 / Apr-Oct" },
    { key: "duration", label: t("landmark.duration"), type: "input", placeholder: "2-4h" },
    { key: "ticket", label: t("landmark.tickets"), type: "input", placeholder: "¥50 / Free" },
    { key: "transport", label: t("landmark.edit.fieldTransport"), type: "input", placeholder: t("landmark.edit.transportPlaceholder") },
    { key: "tips", label: t("landmark.edit.fieldTips"), type: "textarea", placeholder: t("landmark.edit.tipsPlaceholder") },
    { key: "openingHoursInfo", label: t("landmark.openingHours"), type: "input", placeholder: "08:00-18:00" },
    { key: "altitude", label: t("landmark.altitude"), type: "input", placeholder: "1,100m" },
    { key: "geology", label: t("landmark.geology"), type: "input", placeholder: "Karst / 喀斯特" },
    { key: "yearBuilt", label: t("landmark.yearBuilt"), type: "input", placeholder: "1987 / 明代" },
  ];

  return (
    <div className="min-h-screen bg-background">
      {/* Header */}
      <div className="sticky top-0 z-50 bg-background/95 backdrop-blur-sm border-b px-4 py-3">
        <div className="max-w-4xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-2">
            <Pencil className="w-4 h-4 text-primary" />
            <h2 className="font-semibold text-foreground">{t("landmark.edit.title")}</h2>
          </div>
          <div className="flex items-center gap-2">
            <Select value={editLang} onValueChange={setEditLang}>
              <SelectTrigger className="w-[120px] h-8 text-xs">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                {EDIT_LANGUAGES.map(lang => (
                  <SelectItem key={lang.value} value={lang.value}>{lang.label}</SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>
        </div>
      </div>

      {/* Edit Form */}
      <div className="max-w-4xl mx-auto px-4 py-6 space-y-6">
        <p className="text-sm text-muted-foreground">{t("landmark.edit.instruction")}</p>

        <div className="bg-primary/5 border border-primary/10 rounded-lg p-3 flex items-start gap-2">
          <Pencil className="w-4 h-4 text-primary mt-0.5 shrink-0" />
          <p className="text-xs text-muted-foreground">
            {t("landmark.edit.activityRequired")}
            {" "}
            <a href="/activity/67a454b9-7c85-4b7d-bbf4-2174e27317a8" className="text-primary underline hover:no-underline">
              {t("addLandmark.goToActivity")}
            </a>
          </p>
        </div>

        {editableFields.map(({ key, label, type, placeholder }) => (
          <div key={key} className="space-y-2">
            <Label className="text-sm font-medium">{label}</Label>
            {type === "textarea" ? (
              <Textarea
                value={fields[key]}
                onChange={(e) => updateField(key, e.target.value)}
                placeholder={placeholder}
                className="min-h-[100px] text-sm"
              />
            ) : (
              <Input
                value={fields[key]}
                onChange={(e) => updateField(key, e.target.value)}
                placeholder={placeholder}
                className="h-9 text-sm"
              />
            )}
            {originals[key] && fields[key] !== originals[key] && (
              <p className="text-xs text-muted-foreground">
                {t("landmark.edit.originalValue")}: <span className="line-through">{originals[key]}</span>
              </p>
            )}
          </div>
        ))}
      </div>

      {/* Floating toolbar */}
      <div className="fixed bottom-0 inset-x-0 z-50 bg-background/95 backdrop-blur-md border-t shadow-lg">
        <div className="max-w-4xl mx-auto px-4 py-3 flex items-center justify-between gap-3">
          <p className="text-xs text-muted-foreground hidden sm:block">
            {t("landmark.edit.reviewNote")}
          </p>
          <div className="flex items-center gap-2 ml-auto">
            <Button variant="outline" size="sm" onClick={onClose} disabled={isSubmitting}>
              <X className="w-4 h-4 mr-1" />
              {t("common.cancel")}
            </Button>
            <Button size="sm" onClick={handleSave} disabled={isSubmitting}>
              {isSubmitting ? (
                <Loader2 className="w-4 h-4 mr-1 animate-spin" />
              ) : (
                <Save className="w-4 h-4 mr-1" />
              )}
              {t("common.save")}
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
};
