import { useState, useRef, useEffect, lazy, Suspense, useCallback, useMemo } from "react";
import { useNavigate } from "react-router-dom";
import { useTranslation } from "react-i18next";
import { useAuth } from "@/contexts/AuthContext";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent } from "@/components/ui/card";
import {
  AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent,
  AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { Separator } from "@/components/ui/separator";
import {
  ChevronLeft, Heart, Share2, MapPin, Star, Languages,
  Loader2, Clock, Ticket, RotateCcw, Phone, Mail, Globe,
  CalendarClock, BadgeCheck, Train, Bus, ArrowRight,
  Wifi, Luggage, CreditCard, Accessibility, Navigation,
  ExternalLink, Info, Lightbulb, ShoppingBag,
} from "lucide-react";
import mapboxgl from "mapbox-gl";
import "mapbox-gl/dist/mapbox-gl.css";
import { BuildingStorySection } from "@/components/BuildingStorySection";
import { calculateDistance, getUserLocation } from "@/lib/geolocation";
import { NearbyRestaurantsSection } from "@/components/NearbyRestaurantsSection";
import { NearbyLandmarks } from "@/components/NearbyLandmarks";
import { useDishImages } from "@/hooks/useDishImages";
import { Images } from "lucide-react";
import ImagePreviewModal from "@/components/ImagePreviewModal";
import { PullToRefresh } from "@/components/PullToRefresh";
import RestaurantRating from "@/components/RestaurantRating";
import { Loader2 as Loader2Icon } from "lucide-react";
import type { StationInfo, StationRoute, StationFacility, StationTransfer } from "@/components/admin/StationInfoEditor";

const RestaurantComments = lazy(() => import("@/components/RestaurantComments"));

const FACILITY_ICONS: Record<string, React.ReactNode> = {
  luggage: <Luggage className="w-4 h-4" />,
  wifi: <Wifi className="w-4 h-4" />,
  atm: <CreditCard className="w-4 h-4" />,
  wheelchair: <Accessibility className="w-4 h-4" />,
  restroom: <Info className="w-4 h-4" />,
  food: <ShoppingBag className="w-4 h-4" />,
  parking: <Info className="w-4 h-4" />,
  taxi: <Info className="w-4 h-4" />,
};

const TRANSFER_ICONS: Record<string, string> = {
  metro: "🚇",
  bus: "🚌",
  tram: "🚋",
  ferry: "⛴️",
};

interface StationDetailPageProps {
  restaurant: any;
  localizedRestaurant: any;
  onBack: () => void;
  user: any;
  isFavorite: boolean;
  onToggleFavorite: () => void;
  onShare: () => void;
  onRefresh: () => Promise<void>;
}

export const StationDetailPage = ({
  restaurant,
  localizedRestaurant,
  onBack,
  user,
  isFavorite,
  onToggleFavorite,
  onShare,
  onRefresh,
}: StationDetailPageProps) => {
  const { i18n, t } = useTranslation();
  const { user: authUser } = useAuth();
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const { data: photoWallImages = [] } = useDishImages(restaurant.id);
  const [translatedName, setTranslatedName] = useState("");
  const [translatedDesc, setTranslatedDesc] = useState("");
  const [isAutoTranslating, setIsAutoTranslating] = useState(false);
  const [showTranslation, setShowTranslation] = useState(true);
  const [showMapHint, setShowMapHint] = useState(false);
  const [showLoginDialog, setShowLoginDialog] = useState(false);
  const navigate = useNavigate();
  const mapHintTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const mapContainer = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<mapboxgl.Map | null>(null);
  const lang = i18n.language;

  const requireLogin = useCallback((action: () => void) => {
    if (!authUser) {
      setShowLoginDialog(true);
    } else {
      action();
    }
  }, [authUser]);

  // User distance
  const [userLocation, setUserLocation] = useState<{ lat: number; lng: number } | null>(null);
  useEffect(() => {
    getUserLocation().then(pos => {
      setUserLocation({ lat: pos.coords.latitude, lng: pos.coords.longitude });
    }).catch(() => {});
  }, []);

  const distanceKm = useMemo(() => {
    if (!userLocation || !restaurant.lat || !restaurant.lng) return null;
    return calculateDistance(userLocation.lat, userLocation.lng, restaurant.lat, restaurant.lng);
  }, [userLocation, restaurant.lat, restaurant.lng]);

  // Station info from landmark_info
  const stationInfo: StationInfo = useMemo(() => {
    const li = restaurant.landmark_info;
    if (!li || typeof li !== 'object') return {};
    // Support both new station_info and legacy practical_info
    if (li.station_info) return li.station_info as StationInfo;
    // Migrate from legacy practical_info
    if (li.practical_info) {
      const pi = li.practical_info as any;
      return {
        ticketInfo: pi.ticket_info || "",
        openingHours: pi.opening_hours || "",
        tips: pi.tips || "",
        transfers: pi.metro_connection ? [{ type: "metro", lines: pi.metro_connection, details: "" }] : [],
        routes: pi.key_routes ? [{ destination: pi.key_routes, duration: "", price: "", frequency: "" }] : [],
      } as StationInfo;
    }
    return {};
  }, [restaurant.landmark_info]);

  const rawRoutes = stationInfo.routes || [];
  const rawFacilities = (stationInfo.facilities || []).filter(f => f.available);
  const rawTransfers = stationInfo.transfers || [];

  // Auto-translate
  const isCoreLang = lang === "zh" || lang === "en" || lang === "pt";

  // Auto-translate dynamic station strings (routes/transfers/facilities/hours/tickets) for non-core langs
  const [translatedStation, setTranslatedStation] = useState<{
    openingHours?: string; ticketInfo?: string;
    routes: StationRoute[]; transfers: StationTransfer[]; facilities: StationFacility[];
  } | null>(null);

  useEffect(() => {
    setTranslatedStation(null);
    if (isCoreLang) return;

    const sep = "\n---X---\n";
    const segs: string[] = [];
    const push = (s?: string | null) => { segs.push(s ? String(s) : ""); };

    push(stationInfo.openingHours);
    push(stationInfo.ticketInfo);
    rawRoutes.forEach(r => { push(r.destination); push(r.duration); push(r.price); push(r.frequency); push(r.operator); });
    rawTransfers.forEach(tr => { push(tr.lines); push(tr.details); });
    rawFacilities.forEach(f => { push(f.label); });

    if (segs.every(s => !s)) return;

    let cancelled = false;
    supabase.functions.invoke("translate-content", {
      body: { text: segs.join(sep), targetLang: lang },
    }).then(({ data, error }) => {
      if (cancelled || error || !data?.translatedText) return;
      const out = String(data.translatedText).split(sep);
      let i = 0;
      const next = () => out[i++] ?? "";
      const openingHours = next();
      const ticketInfo = next();
      const routes: StationRoute[] = rawRoutes.map(r => ({
        ...r,
        destination: next() || r.destination,
        duration: next() || r.duration,
        price: next() || r.price,
        frequency: next() || r.frequency,
        operator: next() || r.operator,
      }));
      const transfers: StationTransfer[] = rawTransfers.map(tr => ({
        ...tr,
        lines: next() || tr.lines,
        details: next() || tr.details,
      }));
      const facilities: StationFacility[] = rawFacilities.map(f => ({
        ...f,
        label: next() || f.label,
      }));
      setTranslatedStation({
        openingHours: openingHours || stationInfo.openingHours,
        ticketInfo: ticketInfo || stationInfo.ticketInfo,
        routes, transfers, facilities,
      });
    });
    return () => { cancelled = true; };
  }, [lang, restaurant.id, isCoreLang]);

  const routes = translatedStation?.routes ?? rawRoutes;
  const facilities = translatedStation?.facilities ?? rawFacilities;
  const transfers = translatedStation?.transfers ?? rawTransfers;
  const displayOpeningHours = translatedStation?.openingHours ?? stationInfo.openingHours;
  const displayTicketInfo = translatedStation?.ticketInfo ?? stationInfo.ticketInfo;
  const localizedName = localizedRestaurant.name || "";
  const localizedDesc = localizedRestaurant.description || "";

  useEffect(() => {
    setTranslatedName("");
    setTranslatedDesc("");
    setShowTranslation(true);
    if (isCoreLang) { setIsAutoTranslating(false); return; }
    if (!localizedName && !localizedDesc) return;

    const parts = [localizedName];
    if (localizedDesc) parts.push(localizedDesc);
    const combined = parts.join("\n---SECTION---\n");

    let cancelled = false;
    setIsAutoTranslating(true);
    supabase.functions.invoke("translate-content", {
      body: { text: combined, targetLang: lang },
    }).then(({ data, error }) => {
      if (cancelled) return;
      if (error) { setIsAutoTranslating(false); return; }
      const translated = (data?.translatedText || "").split("\n---SECTION---\n");
      setTranslatedName(translated[0]?.trim() || "");
      if (localizedDesc) setTranslatedDesc(translated[1]?.trim() || "");
      setShowTranslation(true);
      setIsAutoTranslating(false);
    });
    return () => { cancelled = true; };
  }, [lang, restaurant.id, localizedName, localizedDesc]);

  // Map
  const lat = restaurant.lat;
  const lng = restaurant.lng;

  useEffect(() => {
    if (!mapContainer.current || mapInstance.current || !lat || !lng) return;
    const token = import.meta.env.VITE_MAPBOX_TOKEN;
    if (!token) return;

    mapboxgl.accessToken = token;
    const map = new mapboxgl.Map({
      container: mapContainer.current,
      style: "mapbox://styles/mapbox/outdoors-v12",
      center: [lng, lat],
      zoom: 14,
      attributionControl: false,
      scrollZoom: false,
      dragPan: false,
      touchZoomRotate: false,
      doubleClickZoom: false,
      touchPitch: false,
      dragRotate: false,
    });

    const handleWheel = (e: WheelEvent) => {
      if (e.ctrlKey || e.metaKey) { e.preventDefault(); map.scrollZoom.enable(); } else { map.scrollZoom.disable(); }
    };
    map.getCanvas().addEventListener('wheel', handleWheel, { passive: false });
    map.on('touchstart', (e) => { if (e.originalEvent.touches.length >= 2) { map.dragPan.enable(); map.touchZoomRotate.enable(); } });
    map.on('touchend', () => { map.dragPan.disable(); map.touchZoomRotate.disable(); });

    new mapboxgl.Marker({ color: "#005C53" }).setLngLat([lng, lat]).addTo(map);
    map.addControl(new mapboxgl.NavigationControl({ showCompass: false }), "top-right");
    mapInstance.current = map;

    return () => { map.remove(); mapInstance.current = null; };
  }, [lat, lng]);

  const isTrainStation = (restaurant.type_en || []).includes("Train Station");
  const StationIcon = isTrainStation ? Train : Bus;

  return (
    <PullToRefresh onRefresh={onRefresh}>
      <div className="min-h-screen bg-background">
        {/* Hero */}
        <div className="relative h-[50vh] md:h-[60vh] overflow-hidden">
          <img
            src={restaurant.cover_image_url || restaurant.image_url}
            alt={localizedRestaurant.name}
            className="w-full h-full object-cover"
            loading="eager"
          />
          <div className="absolute inset-0 bg-gradient-to-t from-background via-background/40 to-transparent" />

          {/* Top nav */}
          <div className="absolute top-0 inset-x-0 p-4 flex justify-between items-start z-10">
            <Button variant="secondary" size="icon" className="backdrop-blur-md bg-background/40 border-0 shadow-lg" onClick={onBack}>
              <ChevronLeft className="w-5 h-5" />
            </Button>
            <div className="flex gap-2">
              <Button variant="secondary" size="icon" className="backdrop-blur-md bg-background/40 border-0 shadow-lg" onClick={() => requireLogin(onToggleFavorite)}>
                <Heart className={`w-5 h-5 ${isFavorite ? "fill-destructive text-destructive" : ""}`} />
              </Button>
              <Button variant="secondary" size="icon" className="backdrop-blur-md bg-background/40 border-0 shadow-lg" onClick={onShare}>
                <Share2 className="w-5 h-5" />
              </Button>
            </div>
          </div>

          {/* Hero content */}
          <div className="absolute bottom-0 inset-x-0 p-6 md:p-10 space-y-3">
            <div className="flex items-center gap-2 flex-wrap">
              <Badge className="bg-primary/90 text-primary-foreground border-0 backdrop-blur-sm px-3 py-1">
                <StationIcon className="w-3.5 h-3.5 mr-1.5" />
                {isTrainStation ? t("station.trainStation", "火车站") : t("station.busStation", "长途汽车站")}
              </Badge>
              {stationInfo.operatorName && (
                <Badge variant="outline" className="bg-background/30 backdrop-blur-sm border-border/30 text-primary-foreground px-3 py-1">
                  {stationInfo.operatorName}
                </Badge>
              )}
            </div>
            <h1 className="text-3xl md:text-5xl font-bold text-black tracking-tight" style={{ textShadow: '0 1px 8px rgba(255,255,255,0.5)' }}>
              {(showTranslation && translatedName) ? translatedName : localizedRestaurant.name}
            </h1>
            {(() => {
              const displayed = (showTranslation && translatedName) ? translatedName : localizedRestaurant.name;
              const original = restaurant?.name || "";
              const isDual = original && displayed && original.trim().toLowerCase() !== String(displayed).trim().toLowerCase();
              return (
                <div className="flex items-center gap-3 mt-1 flex-wrap">
                  <button
                    onClick={async () => {
                      if (showTranslation) { setShowTranslation(false); return; }
                      if (translatedName || translatedDesc) { setShowTranslation(true); return; }
                      setIsAutoTranslating(true);
                      try {
                        const parts = [localizedName];
                        if (localizedDesc) parts.push(localizedDesc);
                        const combined = parts.join("\n---SECTION---\n");
                        const { data, error } = await supabase.functions.invoke("translate-content", {
                          body: { text: combined, targetLang: lang },
                        });
                        if (!error && data?.translatedText) {
                          const translated = (data.translatedText || "").split("\n---SECTION---\n");
                          setTranslatedName(translated[0]?.trim() || "");
                          if (localizedDesc) setTranslatedDesc(translated[1]?.trim() || "");
                        }
                        setShowTranslation(true);
                      } catch {}
                      setIsAutoTranslating(false);
                    }}
                    disabled={isAutoTranslating}
                    className={`inline-flex items-center gap-1 px-2.5 py-1 rounded-md text-xs font-medium backdrop-blur-sm transition-colors ${
                      isAutoTranslating ? "text-black/40 cursor-wait"
                      : showTranslation ? "text-primary bg-primary/10"
                      : "text-black/70 hover:text-primary hover:bg-primary/10"
                    }`}
                    style={{ textShadow: 'none' }}
                  >
                    {isAutoTranslating ? <Loader2 className="w-3.5 h-3.5 animate-spin" />
                     : showTranslation ? <RotateCcw className="w-3.5 h-3.5" />
                     : <Languages className="w-3.5 h-3.5" />}
                    {isAutoTranslating ? t("translate.translating") : showTranslation ? t("translate.showOriginal") : t("translate.button")}
                  </button>
                  {isDual && <p className="text-sm text-black/60" style={{ textShadow: '0 1px 4px rgba(255,255,255,0.4)' }}>{original}</p>}
                </div>
              );
            })()}
            <div className="flex flex-col gap-1">
              <div className="flex items-start gap-2 text-black/70 text-xs" style={{ textShadow: '0 1px 4px rgba(255,255,255,0.4)' }}>
                <MapPin className="w-3.5 h-3.5 shrink-0 mt-0.5" />
                <span className="flex-1 min-w-0 break-words">{restaurant.address}</span>
              </div>
              {distanceKm != null && (
                <div className="flex items-center gap-1 ml-5.5 text-xs font-medium text-primary">
                  <Navigation className="w-3 h-3" />
                  <span>{distanceKm < 1 ? `${(distanceKm * 1000).toFixed(0)} m` : `${distanceKm.toFixed(1)} km`}</span>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Content */}
        <div className="max-w-4xl mx-auto px-4 md:px-8 -mt-4 relative z-10 space-y-8 pb-16">

          {/* Quick Action: Buy Ticket */}
          {stationInfo.ticketUrl && (
            <a
              href={stationInfo.ticketUrl}
              target="_blank"
              rel="noopener noreferrer"
              className="flex items-center justify-center gap-2 w-full h-12 rounded-xl bg-primary text-primary-foreground font-medium shadow-lg hover:opacity-90 transition-opacity"
            >
              <Ticket className="w-5 h-5" />
              {t("station.buyTicket", "在线购票")}
              <ExternalLink className="w-4 h-4" />
            </a>
          )}

          {/* Overview Card */}
          <Card className="border-0 shadow-xl bg-card/95 backdrop-blur-sm overflow-hidden relative">
            {lat && lng && (
              <div className="absolute top-4 right-4 md:top-6 md:right-6 z-10">
                <NearbyLandmarks lat={lat} lng={lng} restaurantId={restaurant.id} />
              </div>
            )}
            <CardContent className="p-6 md:p-8">
              <div className="flex items-start gap-3 mb-4">
                <div className="p-2.5 rounded-xl bg-primary/10">
                  <StationIcon className="w-5 h-5 text-primary" />
                </div>
                <div className="flex-1">
                  <h2 className="text-lg font-semibold text-foreground">{t("station.overview", "车站概况")}</h2>
                </div>
              </div>

              {/* Quick info grid */}
              {(() => {
                const items = [
                  stationInfo.openingHours && { icon: <CalendarClock className="w-4 h-4 text-primary" />, label: t("station.hours", "营运时间"), value: displayOpeningHours || stationInfo.openingHours },
                  stationInfo.ticketInfo && { icon: <Ticket className="w-4 h-4 text-primary" />, label: t("station.ticketInfo", "购票方式"), value: displayTicketInfo || stationInfo.ticketInfo },
                ].filter(Boolean) as { icon: React.ReactNode; label: string; value: string }[];
                if (items.length === 0) return null;
                return (
                  <div className={`grid ${items.length === 1 ? 'grid-cols-1 max-w-[240px]' : 'grid-cols-2'} gap-3 mb-5`}>
                    {items.map((item, i) => (
                      <div key={i} className="flex flex-col items-center gap-1.5 p-3 rounded-xl bg-muted/50">
                        {item.icon}
                        <span className="text-xs text-muted-foreground">{item.label}</span>
                        <span className="text-sm font-medium text-foreground text-center">{item.value}</span>
                      </div>
                    ))}
                  </div>
                );
              })()}

              <p className="text-muted-foreground leading-relaxed text-[15px]">
                {isAutoTranslating ? (
                  <span className="flex items-center gap-2 text-muted-foreground/60">
                    <Loader2 className="w-4 h-4 animate-spin" />
                    {t("common.translating")}
                  </span>
                ) : (
                  (showTranslation && translatedDesc) ? translatedDesc : localizedRestaurant.description
                )}
              </p>
            </CardContent>
          </Card>

          {/* Popular Routes */}
          {routes.length > 0 && (
            <section className="space-y-4">
              <div className="flex items-center gap-3">
                <div className="p-2.5 rounded-xl bg-primary/10">
                  <Train className="w-5 h-5 text-primary" />
                </div>
                <div>
                  <h2 className="text-xl font-bold text-foreground">{t("station.popularRoutes", "热门路线")}</h2>
                  <p className="text-sm text-muted-foreground">{t("station.routesDesc", "从这里出发的主要路线")}</p>
                </div>
              </div>
              <div className="space-y-3">
                {routes.map((route, idx) => (
                  <Card key={idx} className="border shadow-md hover:shadow-lg transition-shadow">
                    <CardContent className="p-4">
                      <div className="flex items-center justify-between">
                        <div className="flex items-center gap-3 flex-1 min-w-0">
                          <div className="p-2 rounded-lg bg-muted">
                            <StationIcon className="w-4 h-4 text-muted-foreground" />
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className="flex items-center gap-2">
                              <span className="font-medium text-foreground text-sm truncate">{localizedRestaurant.name?.split(/[（(]/)?.[0]?.trim()}</span>
                              <ArrowRight className="w-3.5 h-3.5 text-muted-foreground shrink-0" />
                              <span className="font-medium text-foreground text-sm truncate">{route.destination}</span>
                            </div>
                            {route.operator && (
                              <span className="text-xs text-muted-foreground">{route.operator}</span>
                            )}
                          </div>
                        </div>
                      </div>
                      <div className="flex items-center gap-4 mt-3 ml-11">
                        {route.duration && (
                          <div className="flex items-center gap-1 text-xs text-muted-foreground">
                            <Clock className="w-3.5 h-3.5" />
                            <span>{route.duration}</span>
                          </div>
                        )}
                        {route.price && (
                          <div className="flex items-center gap-1 text-xs text-muted-foreground">
                            <Ticket className="w-3.5 h-3.5" />
                            <span>{route.price}</span>
                          </div>
                        )}
                        {route.frequency && (
                          <div className="flex items-center gap-1 text-xs text-primary font-medium">
                            <CalendarClock className="w-3.5 h-3.5" />
                            <span>{route.frequency}</span>
                          </div>
                        )}
                      </div>
                    </CardContent>
                  </Card>
                ))}
              </div>
            </section>
          )}

          {/* Facilities */}
          {facilities.length > 0 && (
            <section className="space-y-4">
              <div className="flex items-center gap-3">
                <div className="p-2.5 rounded-xl bg-accent">
                  <Info className="w-5 h-5 text-accent-foreground" />
                </div>
                <h2 className="text-xl font-bold text-foreground">{t("station.facilities", "站内设施")}</h2>
              </div>
              <div className="flex flex-wrap gap-2">
                {facilities.map((facility) => (
                  <Badge key={facility.key} variant="secondary" className="px-3 py-1.5 text-sm gap-1.5">
                    {FACILITY_ICONS[facility.key] || <Info className="w-4 h-4" />}
                    {facility.label}
                  </Badge>
                ))}
              </div>
            </section>
          )}

          {/* Transfer Guide */}
          {transfers.length > 0 && (
            <section className="space-y-4">
              <div className="flex items-center gap-3">
                <div className="p-2.5 rounded-xl bg-secondary">
                  <Bus className="w-5 h-5 text-secondary-foreground" />
                </div>
                <div>
                  <h2 className="text-xl font-bold text-foreground">{t("station.transferGuide", "换乘指引")}</h2>
                  <p className="text-sm text-muted-foreground">{t("station.transferDesc", "可换乘的公共交通")}</p>
                </div>
              </div>
              <Card className="border-0 shadow-lg">
                <CardContent className="p-5 space-y-3">
                  {transfers.map((transfer, idx) => (
                    <div key={idx} className="flex items-start gap-3">
                      <span className="text-xl shrink-0 mt-0.5">{TRANSFER_ICONS[transfer.type] || "🚌"}</span>
                      <div className="flex-1">
                        <p className="font-medium text-sm text-foreground">{transfer.lines}</p>
                        {transfer.details && (
                          <p className="text-muted-foreground text-xs mt-0.5">{transfer.details}</p>
                        )}
                      </div>
                    </div>
                  ))}
                </CardContent>
              </Card>
            </section>
          )}

          <Separator className="my-2" />

          {/* Building Story & I Ching */}
          <section className="space-y-5">
            <div className="flex items-center gap-3">
              <div className="p-2.5 rounded-xl bg-secondary">
                <StationIcon className="w-5 h-5 text-secondary-foreground" />
              </div>
              <div className="flex-1">
                <h2 className="text-xl font-bold text-foreground">{t("landmark.historyIChing")}</h2>
                <p className="text-sm text-muted-foreground">{t("landmark.historyIChingSubtitle")}</p>
              </div>
            </div>
            <Card className="border-0 shadow-lg overflow-hidden">
              <CardContent className="p-0">
                <BuildingStorySection restaurant={restaurant} variant="card" />
              </CardContent>
            </Card>
          </section>

          {/* Nearby Restaurants */}
          {lat && lng && (
            <NearbyRestaurantsSection
              lat={lat}
              lng={lng}
              currentRestaurantId={restaurant.id}
              landmarkName={localizedRestaurant.name}
            />
          )}

          {/* Photo Wall */}
          {photoWallImages.length > 0 && (
            <section className="space-y-4">
              <div className="flex items-center gap-3">
                <div className="p-2.5 rounded-xl bg-primary/10">
                  <Images className="w-5 h-5 text-primary" />
                </div>
                <div>
                  <h2 className="text-xl font-bold text-foreground">{t("landmark.photoWall")}</h2>
                  <p className="text-sm text-muted-foreground">{t("landmark.photoWallDesc")}</p>
                </div>
              </div>
              <div className={`grid gap-3 ${photoWallImages.length === 1 ? 'grid-cols-1' : photoWallImages.length === 2 ? 'grid-cols-2' : 'grid-cols-3'}`}>
                {photoWallImages.slice(0, 3).map((img) => (
                  <div key={img.id} className="relative rounded-xl overflow-hidden cursor-pointer group aspect-[4/3]" onClick={() => setPreviewImage(img.image_url)}>
                    <img src={img.image_url} alt="" className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-105" loading="lazy" />
                    <div className="absolute inset-0 bg-black/0 group-hover:bg-black/10 transition-colors" />
                  </div>
                ))}
              </div>
            </section>
          )}

          {/* Location & Contact */}
          <section className="space-y-4">
            <div className="flex items-center gap-3">
              <div className="p-2.5 rounded-xl bg-muted">
                <MapPin className="w-5 h-5 text-muted-foreground" />
              </div>
              <h2 className="text-xl font-bold text-foreground">{t("station.locationContact", "位置与联系")}</h2>
            </div>
            <Card className="border-0 shadow-lg">
              <CardContent className="p-5 space-y-4">
                <div className="flex items-start gap-3">
                  <MapPin className="w-5 h-5 text-muted-foreground mt-0.5 shrink-0" />
                  <div>
                    <p className="font-medium text-sm text-foreground">{t("landmark.location")}</p>
                    <p className="text-muted-foreground text-sm mt-0.5">{restaurant.address}</p>
                  </div>
                </div>
                {restaurant.phone && (
                  <>
                    <Separator />
                    <div className="flex items-start gap-3">
                      <Phone className="w-5 h-5 text-muted-foreground mt-0.5 shrink-0" />
                      <div>
                        <p className="font-medium text-sm text-foreground">{t("landmark.phone")}</p>
                        <a href={`tel:${restaurant.phone}`} className="text-primary text-sm mt-0.5 hover:underline">{restaurant.phone}</a>
                      </div>
                    </div>
                  </>
                )}
                {(stationInfo.operatorUrl || restaurant.website_url) && (
                  <>
                    <Separator />
                    <div className="flex items-start gap-3">
                      <Globe className="w-5 h-5 text-muted-foreground mt-0.5 shrink-0" />
                      <div>
                        <p className="font-medium text-sm text-foreground">{t("landmark.website")}</p>
                        <a href={stationInfo.operatorUrl || restaurant.website_url} target="_blank" rel="noopener noreferrer" className="text-primary text-sm mt-0.5 hover:underline break-all">
                          {(stationInfo.operatorUrl || restaurant.website_url || "").replace(/^https?:\/\//, '')}
                        </a>
                      </div>
                    </div>
                  </>
                )}
                {restaurant.opening_hours && (
                  <>
                    <Separator />
                    <div className="flex items-start gap-3">
                      <CalendarClock className="w-5 h-5 text-muted-foreground mt-0.5 shrink-0" />
                      <div>
                        <p className="font-medium text-sm text-foreground">{t("landmark.openingHours")}</p>
                        <div className="text-muted-foreground text-sm mt-0.5 space-y-0.5">
                          {typeof restaurant.opening_hours === 'object' && restaurant.opening_hours !== null
                            ? Object.entries(restaurant.opening_hours).map(([day, hours]) => (
                                <div key={day}><span className="font-medium">{day}:</span> {String(hours)}</div>
                              ))
                            : <span>{String(restaurant.opening_hours)}</span>
                          }
                        </div>
                      </div>
                    </div>
                  </>
                )}
              </CardContent>
            </Card>

            {/* Tips */}
            {stationInfo.tips && (
              <Card className="border-0 shadow-md bg-accent/50">
                <CardContent className="p-4 flex items-start gap-3">
                  <Lightbulb className="w-5 h-5 text-accent-foreground mt-0.5 shrink-0" />
                  <div>
                    <p className="font-medium text-sm text-foreground">{t("station.tips", "旅客提示")}</p>
                    <p className="text-muted-foreground text-sm mt-1 whitespace-pre-line">{stationInfo.tips}</p>
                  </div>
                </CardContent>
              </Card>
            )}

            {/* Map */}
            {lat && lng && (
              <div className="space-y-3">
                <div
                  className="rounded-xl overflow-hidden border border-border shadow-lg relative"
                  style={{ height: 240 }}
                  onWheel={(e) => {
                    if (!e.ctrlKey && !e.metaKey) {
                      setShowMapHint(true);
                      if (mapHintTimer.current) clearTimeout(mapHintTimer.current);
                      mapHintTimer.current = setTimeout(() => setShowMapHint(false), 2000);
                    }
                  }}
                  onTouchStart={(e) => {
                    if (e.touches.length < 2) {
                      setShowMapHint(true);
                      if (mapHintTimer.current) clearTimeout(mapHintTimer.current);
                      mapHintTimer.current = setTimeout(() => setShowMapHint(false), 2000);
                    }
                  }}
                >
                  <div ref={mapContainer} className="w-full h-full" />
                  {showMapHint && (
                    <div className="absolute inset-0 z-20 flex items-center justify-center bg-foreground/40 pointer-events-none transition-opacity">
                      <span className="text-sm text-white bg-black/70 px-4 py-2 rounded-full">
                        {'ontouchstart' in window
                          ? t("map.scrollHintTouch")
                          : t("map.scrollHintDesktop")}
                      </span>
                    </div>
                  )}
                </div>
                <a
                  href={`https://www.google.com/maps/dir/?api=1&destination=${lat},${lng}`}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="inline-flex items-center justify-center w-full h-10 px-4 rounded-md border border-input bg-background text-sm font-medium hover:bg-secondary hover:text-secondary-foreground transition-colors"
                >
                  <MapPin className="w-4 h-4 mr-1.5" />
                  {t("landmark.navigate")}
                </a>
              </div>
            )}
          </section>

          {/* Rating */}
          <Separator />
          <RestaurantRating restaurantId={restaurant.id} />

          {/* Comments */}
          <Separator />
          <Suspense fallback={
            <div className="flex items-center justify-center py-12">
              <Loader2Icon className="w-8 h-8 animate-spin text-primary" />
            </div>
          }>
            <RestaurantComments restaurantId={restaurant.id} />
          </Suspense>
        </div>

        <ImagePreviewModal isOpen={!!previewImage} onClose={() => setPreviewImage(null)} imageUrl={previewImage || ""} />

        {/* Login Dialog */}
        <AlertDialog open={showLoginDialog} onOpenChange={setShowLoginDialog}>
          <AlertDialogContent>
            <AlertDialogHeader>
              <AlertDialogTitle>{t("activities.loginRequired")}</AlertDialogTitle>
              <AlertDialogDescription>{t("activities.loginRequiredMessage")}</AlertDialogDescription>
            </AlertDialogHeader>
            <AlertDialogFooter>
              <AlertDialogCancel>{t("common.cancel")}</AlertDialogCancel>
              <AlertDialogAction onClick={() => navigate("/auth")}>{t("activities.goToLogin")}</AlertDialogAction>
            </AlertDialogFooter>
          </AlertDialogContent>
        </AlertDialog>
      </div>
    </PullToRefresh>
  );
};
