import { useState, useRef, useEffect, lazy, Suspense, useCallback, useMemo } from "react";
import { useNavigate } from "react-router-dom";

import { useTranslation } from "react-i18next";
import { useLocalizedContent } from "@/hooks/useLocalizedContent";
import { useAuth } from "@/contexts/AuthContext";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent } from "@/components/ui/card";
import {
  AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent,
  AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { Separator } from "@/components/ui/separator";
import {
  ChevronLeft, Heart, Share2, MapPin, Star, Languages,
  Loader2, Mountain, Compass, Camera, BookOpen,
  Landmark as LandmarkIcon, Clock, Ticket, CalendarDays,
  RotateCcw, Phone, Mail, Globe, CalendarClock, BadgeCheck, Pencil,
  Bus, Lightbulb
} from "lucide-react";
import { LandmarkEditMode } from "@/components/LandmarkEditMode";
import LandmarkEditChoiceDialog from "@/components/LandmarkEditChoiceDialog";
import LandmarkAIEditPanel from "@/components/LandmarkAIEditPanel";
import { DraftPublishBanner } from "@/components/DraftPublishBanner";
import mapboxgl from "mapbox-gl";
import "mapbox-gl/dist/mapbox-gl.css";
import { BuildingStorySection } from "@/components/BuildingStorySection";
import { calculateDistance, getUserLocation } from "@/lib/geolocation";
import { Navigation } from "lucide-react";
import { CheckInButton } from "@/components/CheckInButton";

import { NearbyRestaurantsSection } from "@/components/NearbyRestaurantsSection";
import { NearbyLandmarks } from "@/components/NearbyLandmarks";
import { useDishImages } from "@/hooks/useDishImages";
import { Images } from "lucide-react";
import ImagePreviewModal from "@/components/ImagePreviewModal";
import { PullToRefresh } from "@/components/PullToRefresh";
import RestaurantRating from "@/components/RestaurantRating";
import { Loader2 as Loader2Icon } from "lucide-react";

const RestaurantComments = lazy(() => import("@/components/RestaurantComments"));

// Scenic spot type matching DB structure
interface ScenicSpot {
  id: string;
  titleZh: string;
  titleEn: string;
  titlePt: string;
  descZh: string;
  descEn: string;
  descPt: string;
  image: string;
}

interface LandmarkDetailPageProps {
  restaurant: any;
  localizedRestaurant: any;
  onBack: () => void;
  user: any;
  isFavorite: boolean;
  onToggleFavorite: () => void;
  onShare: () => void;
  onRefresh: () => Promise<void>;
}

export const LandmarkDetailPage = ({
  restaurant,
  localizedRestaurant,
  onBack,
  user,
  isFavorite,
  onToggleFavorite,
  onShare,
  onRefresh,
}: LandmarkDetailPageProps) => {
  const { i18n, t } = useTranslation();
  const { user: authUser } = useAuth();
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const { data: photoWallImages = [] } = useDishImages(restaurant.id);
  const [translatedName, setTranslatedName] = useState<string>("");
  const [translatedDesc, setTranslatedDesc] = useState<string>("");
  const [translatedSubtitle, setTranslatedSubtitle] = useState<string>("");
  const [isAutoTranslating, setIsAutoTranslating] = useState(false);
  const [showTranslation, setShowTranslation] = useState(true);
  const [mapInteractive, setMapInteractive] = useState(false);
  const [showMapHint, setShowMapHint] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [showEditChoice, setShowEditChoice] = useState(false);
  const [showAIEdit, setShowAIEdit] = useState(false);
  const [showLoginDialog, setShowLoginDialog] = useState(false);
  const navigate = useNavigate();
  const mapHintTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const mapContainer = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<mapboxgl.Map | null>(null);
  const lang = i18n.language;

  const requireLogin = useCallback((action: () => void) => {
    if (!authUser) {
      setShowLoginDialog(true);
    } else {
      action();
    }
  }, [authUser]);

  // User distance calculation
  const [userLocation, setUserLocation] = useState<{ lat: number; lng: number } | null>(null);

  useEffect(() => {
    getUserLocation().then(pos => {
      setUserLocation({ lat: pos.coords.latitude, lng: pos.coords.longitude });
    }).catch(() => {});
  }, []);

  const distanceKm = useMemo(() => {
    if (!userLocation || !restaurant.lat || !restaurant.lng) return null;
    return calculateDistance(userLocation.lat, userLocation.lng, restaurant.lat, restaurant.lng);
  }, [userLocation, restaurant.lat, restaurant.lng]);

  // Read scenic spots from DB, fallback to empty array
  const scenicSpots: ScenicSpot[] = (restaurant.scenic_spots && Array.isArray(restaurant.scenic_spots))
    ? restaurant.scenic_spots as ScenicSpot[]
    : [];

  // Read landmark info from DB
  const landmarkInfo = (restaurant.landmark_info && typeof restaurant.landmark_info === 'object')
    ? restaurant.landmark_info as any
    : {};

  const getSpotField = (spot: ScenicSpot, field: "title" | "desc") => {
    const key = field === "title" ? "title" : "desc";
    if (lang === "zh") return spot[`${key}Zh` as keyof ScenicSpot] || "";
    if (lang === "pt") return spot[`${key}Pt` as keyof ScenicSpot] || "";
    return spot[`${key}En` as keyof ScenicSpot] || "";
  };

  const getLandmarkField = (base: string) => {
    if (lang === "zh") return landmarkInfo[`${base}Zh`] || landmarkInfo[`${base}En`] || "";
    if (lang === "pt") return landmarkInfo[`${base}Pt`] || landmarkInfo[`${base}En`] || "";
    return landmarkInfo[`${base}En`] || "";
  };

  // Auto-translate name + description + subtitle for non-core languages
  const isCoreLang = lang === "zh" || lang === "en" || lang === "pt";
  const localizedName = localizedRestaurant.name || "";
  const localizedDesc = localizedRestaurant.description || "";

  useEffect(() => {
    // Always clear previous translations on language change
    setTranslatedName("");
    setTranslatedDesc("");
    setTranslatedSubtitle("");
    setShowTranslation(true);

    if (isCoreLang) {
      setIsAutoTranslating(false);
      return;
    }

    if (!localizedName && !localizedDesc) return;

    const subtitle = getLandmarkField("subtitle") || getLandmarkField("category") || "";

    const parts = [localizedName];
    if (localizedDesc) parts.push(localizedDesc);
    if (subtitle) parts.push(subtitle);
    const combined = parts.join("\n---SECTION---\n");

    let cancelled = false;
    setIsAutoTranslating(true);
    supabase.functions.invoke("translate-content", {
      body: { text: combined, targetLang: lang },
    }).then(({ data, error }) => {
      if (cancelled) return;
      if (error) {
        setIsAutoTranslating(false);
        return;
      }
      const translated = (data?.translatedText || "").split("\n---SECTION---\n");
      setTranslatedName(translated[0]?.trim() || "");
      if (localizedDesc) setTranslatedDesc(translated[1]?.trim() || "");
      if (subtitle) setTranslatedSubtitle(translated[localizedDesc ? 2 : 1]?.trim() || "");
      setShowTranslation(true);
      setIsAutoTranslating(false);
    });

    return () => { cancelled = true; };
  }, [lang, restaurant.id, localizedName, localizedDesc]);


  const lat = restaurant.lat;
  const lng = restaurant.lng;

  useEffect(() => {
    if (!mapContainer.current || mapInstance.current || !lat || !lng) return;
    const token = import.meta.env.VITE_MAPBOX_TOKEN;
    if (!token) return;

    mapboxgl.accessToken = token;
    const map = new mapboxgl.Map({
      container: mapContainer.current,
      style: "mapbox://styles/mapbox/outdoors-v12",
      center: [lng, lat],
      zoom: 13,
      attributionControl: false,
      scrollZoom: false,
      dragPan: false,
      touchZoomRotate: false,
      doubleClickZoom: false,
      touchPitch: false,
      dragRotate: false,
    });

    // Enable scroll zoom only with Ctrl/Meta key
    const handleWheel = (e: WheelEvent) => {
      if (e.ctrlKey || e.metaKey) {
        e.preventDefault();
        map.scrollZoom.enable();
      } else {
        map.scrollZoom.disable();
      }
    };
    map.getCanvas().addEventListener('wheel', handleWheel, { passive: false });

    // Enable drag/zoom with two fingers on touch
    map.on('touchstart', (e) => {
      if (e.originalEvent.touches.length >= 2) {
        map.dragPan.enable();
        map.touchZoomRotate.enable();
      }
    });
    map.on('touchend', () => {
      map.dragPan.disable();
      map.touchZoomRotate.disable();
    });

    new mapboxgl.Marker({ color: "#e74c3c" })
      .setLngLat([lng, lat])
      .addTo(map);

    map.addControl(new mapboxgl.NavigationControl({ showCompass: false }), "top-right");
    mapInstance.current = map;

    return () => {
      map.remove();
      mapInstance.current = null;
    };
  }, [lat, lng]);

  if (isEditing) {
    return (
      <LandmarkEditMode
        restaurant={restaurant}
        localizedRestaurant={localizedRestaurant}
        onClose={() => setIsEditing(false)}
        onSaved={() => { setIsEditing(false); onRefresh(); }}
      />
    );
  }

  return (
    <PullToRefresh onRefresh={onRefresh}>
      <div className="min-h-screen bg-background">
        {/* Immersive Hero */}
        <div className="relative h-[55vh] md:h-[65vh] overflow-hidden">
          <img
            src={restaurant.cover_image_url || restaurant.image_url}
            alt={localizedRestaurant.name}
            className="w-full h-full object-cover"
            loading="eager"
          />
          <div className="absolute inset-0 bg-gradient-to-t from-background via-background/40 to-transparent" />
          <div className="absolute inset-0 bg-gradient-to-r from-background/30 to-transparent" />

          {/* Top nav */}
          <div className="absolute top-0 inset-x-0 p-4 flex justify-between items-start z-10">
            <Button variant="secondary" size="icon" className="backdrop-blur-md bg-background/40 border-0 shadow-lg" onClick={onBack}>
              <ChevronLeft className="w-5 h-5" />
            </Button>
            <div className="flex gap-2">
              <Button
                variant="secondary"
                size="icon"
                className="backdrop-blur-md bg-background/40 border-0 shadow-lg"
                onClick={() => requireLogin(() => setShowEditChoice(true))}
                title={t("landmark.edit.title")}
              >
                <Pencil className="w-4 h-4" />
              </Button>
              <CheckInButton
                restaurantId={restaurant.id}
                restaurantLat={Number(restaurant.lat)}
                restaurantLng={Number(restaurant.lng)}
                onLoginRequired={() => setShowLoginDialog(true)}
              />
              <Button
                variant="secondary"
                size="icon"
                className="backdrop-blur-md bg-background/40 border-0 shadow-lg"
                onClick={() => requireLogin(onToggleFavorite)}
              >
                <Heart className={`w-5 h-5 ${isFavorite ? "fill-destructive text-destructive" : ""}`} />
              </Button>
              <Button
                variant="secondary"
                size="icon"
                className="backdrop-blur-md bg-background/40 border-0 shadow-lg"
                onClick={onShare}
              >
                <Share2 className="w-5 h-5" />
              </Button>
            </div>
          </div>

          {/* Hero content */}
          <div className="absolute bottom-0 inset-x-0 p-6 md:p-10 space-y-3">
            <div className="flex items-center gap-2">
              <Badge className="bg-primary/90 text-primary-foreground border-0 backdrop-blur-sm px-3 py-1">
                <LandmarkIcon className="w-3.5 h-3.5 mr-1.5" />
                {t("landmark.scenicSpot")}
              </Badge>
              <Badge variant="outline" className="bg-background/30 backdrop-blur-sm border-border/30 text-primary-foreground px-3 py-1">
                <Star className="w-3.5 h-3.5 mr-1 fill-yellow-400 text-yellow-400" />
                {restaurant.rating || "5.0"}
              </Badge>
              {restaurant.photo_story_zh && restaurant.image_url && (
                <Badge variant="outline" className="bg-background/30 backdrop-blur-sm border-border/30 text-primary-foreground px-3 py-1">
                  <BadgeCheck className="w-3.5 h-3.5 mr-1 text-primary" />
                  {t("restaurants.verifiedLandmark")}
                </Badge>
              )}
            </div>
            <h1 className="text-3xl md:text-5xl font-bold text-black tracking-tight flex items-center gap-2 flex-wrap" style={{ textShadow: '0 1px 8px rgba(255,255,255,0.5)' }}>
              {(showTranslation && translatedName) ? translatedName : localizedRestaurant.name}
              {restaurant.photo_story_zh && restaurant.image_url && (
                <BadgeCheck className="w-7 h-7 text-primary shrink-0" />
              )}
            </h1>
            {/* Show original name when it differs */}
            {(() => {
              const displayed = (showTranslation && translatedName) ? translatedName : localizedRestaurant.name;
              const original = restaurant?.name || "";
              const isDual = original && displayed && original.trim().toLowerCase() !== String(displayed).trim().toLowerCase();
              return (
                <div className="flex items-center gap-3 mt-1 flex-wrap">
                  <button
                    onClick={async () => {
                      if (showTranslation) {
                        setShowTranslation(false);
                        return;
                      }
                      if (translatedName || translatedDesc) {
                        setShowTranslation(true);
                        return;
                      }
                      setIsAutoTranslating(true);
                      try {
                        const subtitle = getLandmarkField("subtitle") || getLandmarkField("category") || "";
                        const parts = [localizedName];
                        if (localizedDesc) parts.push(localizedDesc);
                        if (subtitle) parts.push(subtitle);
                        const combined = parts.join("\n---SECTION---\n");
                        const { data, error } = await supabase.functions.invoke("translate-content", {
                          body: { text: combined, targetLang: lang },
                        });
                        if (!error && data?.translatedText) {
                          const translated = (data.translatedText || "").split("\n---SECTION---\n");
                          setTranslatedName(translated[0]?.trim() || "");
                          if (localizedDesc) setTranslatedDesc(translated[1]?.trim() || "");
                          if (subtitle) setTranslatedSubtitle(translated[localizedDesc ? 2 : 1]?.trim() || "");
                        }
                        setShowTranslation(true);
                      } catch {}
                      setIsAutoTranslating(false);
                    }}
                    disabled={isAutoTranslating}
                    className={`inline-flex items-center gap-1 px-2.5 py-1 rounded-md text-xs font-medium backdrop-blur-sm transition-colors ${
                      isAutoTranslating
                        ? "text-black/40 cursor-wait"
                        : showTranslation
                          ? "text-primary bg-primary/10"
                          : "text-black/70 hover:text-primary hover:bg-primary/10"
                    }`}
                    style={{ textShadow: 'none' }}
                  >
                    {isAutoTranslating ? (
                      <Loader2 className="w-3.5 h-3.5 animate-spin" />
                    ) : showTranslation ? (
                      <RotateCcw className="w-3.5 h-3.5" />
                    ) : (
                      <Languages className="w-3.5 h-3.5" />
                    )}
                    {isAutoTranslating
                      ? t("translate.translating", "翻译中...")
                      : showTranslation
                        ? t("translate.showOriginal", "显示原文")
                        : t("translate.button", "翻译")}
                   </button>
                  {isDual && (
                    <p className="text-sm text-black/60" style={{ textShadow: '0 1px 4px rgba(255,255,255,0.4)' }}>{original}</p>
                  )}
                </div>
              );
            })()}
            <div className="flex flex-col gap-1">
              <div className="flex items-start gap-2 text-black/70 text-xs" style={{ textShadow: '0 1px 4px rgba(255,255,255,0.4)' }}>
                <MapPin className="w-3.5 h-3.5 shrink-0 mt-0.5" />
                <span className="flex-1 min-w-0 break-words">{restaurant.address}</span>
              </div>
              {distanceKm != null && (
                <div className="flex items-center gap-1 ml-5.5 text-xs font-medium text-primary">
                  <Navigation className="w-3 h-3" />
                  <span>{distanceKm < 1 ? `${(distanceKm * 1000).toFixed(0)} m` : `${distanceKm.toFixed(1)} km`}</span>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Draft publish banner */}
        {restaurant.is_draft && restaurant.created_by === authUser?.id && !restaurant.visible && (
          <DraftPublishBanner
            restaurantId={restaurant.id}
            onPublished={onRefresh}
            submissionStatus={(restaurant as any).submission_status}
          />
        )}

        {/* Content */}
        <div className="max-w-4xl mx-auto px-4 md:px-8 -mt-4 relative z-10 space-y-8 pb-16">
          {/* Quick intro card */}
          <Card className="border-0 shadow-xl bg-card/95 backdrop-blur-sm overflow-hidden relative">
            {lat && lng && (
              <div className="absolute top-4 right-4 md:top-6 md:right-6 z-10">
                <NearbyLandmarks lat={lat} lng={lng} restaurantId={restaurant.id} />
              </div>
            )}
            <CardContent className="p-6 md:p-8">
              <div className="flex items-start gap-3 mb-4">
                <div className="p-2.5 rounded-xl bg-primary/10">
                  <Mountain className="w-5 h-5 text-primary" />
                </div>
                <div className="flex-1">
                  <div className="flex items-center gap-2 flex-wrap">
                    <h2 className="text-lg font-semibold text-foreground">
                      {t("landmark.overview")}
                    </h2>
                    {(getLandmarkField("category") || restaurant.type_en?.[0]) && (
                      <Badge variant="secondary" className="text-xs">
                        <LandmarkIcon className="w-3 h-3 mr-1" />
                        {getLandmarkField("category") || localizedRestaurant.type?.[0] || restaurant.type_en?.[0]}
                      </Badge>
                    )}
                  </div>
                  {(getLandmarkField("subtitle") || translatedSubtitle) && (
                    <p className="text-sm text-muted-foreground mt-0.5 italic">
                      {(showTranslation && translatedSubtitle) ? translatedSubtitle : getLandmarkField("subtitle")}
                    </p>
                  )}
                </div>
              </div>

              {/* Practical info grid - adaptive columns */}
              {(() => {
                const infoItems = [
                  getLandmarkField("bestSeason") && { icon: <CalendarDays className="w-4 h-4 text-primary" />, label: t("landmark.bestSeason"), value: getLandmarkField("bestSeason") },
                  getLandmarkField("duration") && { icon: <Clock className="w-4 h-4 text-primary" />, label: t("landmark.duration"), value: getLandmarkField("duration") },
                  getLandmarkField("ticket") && { icon: <Ticket className="w-4 h-4 text-primary" />, label: t("landmark.tickets"), value: getLandmarkField("ticket") },
                  getLandmarkField("builtYear") && { icon: <CalendarDays className="w-4 h-4 text-primary" />, label: t("landmark.builtYear"), value: getLandmarkField("builtYear") },
                  getLandmarkField("altitude") && { icon: <Mountain className="w-4 h-4 text-primary" />, label: t("landmark.altitude", "海拔"), value: getLandmarkField("altitude") },
                  getLandmarkField("geology") && { icon: <LandmarkIcon className="w-4 h-4 text-primary" />, label: t("landmark.geology", "地貌"), value: getLandmarkField("geology") },
                ].filter(Boolean) as { icon: React.ReactNode; label: string; value: string }[];
                if (infoItems.length === 0) return null;
                const colsClass = infoItems.length === 1 ? 'grid-cols-1 max-w-[200px]' : infoItems.length === 2 ? 'grid-cols-2' : 'grid-cols-3';
                return (
                  <div className={`grid ${colsClass} gap-3 mb-5`}>
                    {infoItems.map((item, i) => (
                      <div key={i} className="flex flex-col items-center gap-1.5 p-3 rounded-xl bg-muted/50">
                        {item.icon}
                        <span className="text-xs text-muted-foreground">{item.label}</span>
                        <span className="text-sm font-medium text-foreground text-center">{item.value}</span>
                      </div>
                    ))}
                  </div>
                );
              })()}

              <p className="text-muted-foreground leading-relaxed text-[15px]">
                {isAutoTranslating ? (
                  <span className="flex items-center gap-2 text-muted-foreground/60">
                    <Loader2 className="w-4 h-4 animate-spin" />
                    {t("common.translating", "Translating...")}
                  </span>
                ) : (
                  (showTranslation && translatedDesc) ? translatedDesc : localizedRestaurant.description
                )}
              </p>
            </CardContent>
          </Card>


          {scenicSpots.length > 0 && (
          <section className="space-y-5">
            <div className="flex items-center gap-3">
              <div className="p-2.5 rounded-xl bg-accent">
                <Camera className="w-5 h-5 text-accent-foreground" />
              </div>
              <div>
                <h2 className="text-xl font-bold text-foreground">
                  {t("landmark.scenicHighlights")}
                </h2>
                <p className="text-sm text-muted-foreground">
                  {t("landmark.bestOfLandscape")}
                </p>
              </div>
            </div>

            {/* Featured spot - large */}
            <div
              className="relative rounded-2xl overflow-hidden cursor-pointer group aspect-[16/9]"
              onClick={() => setPreviewImage(scenicSpots[0].image)}
            >
              <img
                src={scenicSpots[0].image}
                alt={getSpotField(scenicSpots[0], "title")}
                className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105"
                loading="lazy"
              />
              <div className="absolute inset-0 bg-gradient-to-t from-black/90 via-black/40 to-black/10" />
              <div className="absolute bottom-0 inset-x-0 p-5 md:p-6">
                <h3 className="text-xl md:text-2xl font-bold text-white mb-1 drop-shadow-lg">
                  {getSpotField(scenicSpots[0], "title")}
                </h3>
                <p className="text-white/90 text-sm drop-shadow-md">{getSpotField(scenicSpots[0], "desc")}</p>
              </div>
            </div>

            {/* Grid of other spots */}
            {scenicSpots.length > 1 && (
            <div className="grid grid-cols-2 gap-3 md:gap-4">
              {scenicSpots.slice(1).map((spot) => (
                <div
                  key={spot.id}
                  className="relative rounded-xl overflow-hidden cursor-pointer group aspect-square"
                  onClick={() => setPreviewImage(spot.image)}
                >
                  <img
                    src={spot.image}
                    alt={getSpotField(spot, "title")}
                    className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-105"
                    loading="lazy"
                  />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/85 via-black/30 to-transparent" />
                  <div className="absolute bottom-0 inset-x-0 p-3 md:p-4">
                    <h3 className="text-sm md:text-base font-semibold text-white leading-tight drop-shadow-md">
                      {getSpotField(spot, "title")}
                    </h3>
                    <p className="text-white/80 text-xs mt-0.5 line-clamp-2 hidden md:block drop-shadow-sm">
                      {getSpotField(spot, "desc")}
                    </p>
                  </div>
                </div>
              ))}
            </div>
            )}
          </section>
          )}


          <Separator className="my-2" />

          {/* Building Story & I Ching */}
          <section className="space-y-5">
            <div className="flex items-center gap-3">
              <div className="p-2.5 rounded-xl bg-secondary">
                <BookOpen className="w-5 h-5 text-secondary-foreground" />
              </div>
              <div className="flex-1">
                <h2 className="text-xl font-bold text-foreground">
                  {t("landmark.historyIChing")}
                </h2>
                <p className="text-sm text-muted-foreground">
                  {t("landmark.historyIChingSubtitle")}
                </p>
              </div>
            </div>

            <Card className="border-0 shadow-lg overflow-hidden">
              <CardContent className="p-0">
                <BuildingStorySection restaurant={restaurant} variant="card" />
              </CardContent>
            </Card>
          </section>

          {/* Nearby Restaurants */}
          {lat && lng && (
            <NearbyRestaurantsSection
              lat={lat}
              lng={lng}
              currentRestaurantId={restaurant.id}
              landmarkName={localizedRestaurant.name}
            />
          )}

          {/* Photo Wall */}
          {photoWallImages.length > 0 && (
            <section className="space-y-4">
              <div className="flex items-center gap-3">
                <div className="p-2.5 rounded-xl bg-primary/10">
                  <Images className="w-5 h-5 text-primary" />
                </div>
                <div>
                  <h2 className="text-xl font-bold text-foreground">
                    {t("landmark.photoWall", "实景照片")}
                  </h2>
                  <p className="text-sm text-muted-foreground">
                    {t("landmark.photoWallDesc", "这座建筑的街景与细节")}
                  </p>
                </div>
              </div>
              <div className={`grid gap-3 ${photoWallImages.length === 1 ? 'grid-cols-1' : photoWallImages.length === 2 ? 'grid-cols-2' : 'grid-cols-3'}`}>
                {photoWallImages.slice(0, 3).map((img) => (
                  <div
                    key={img.id}
                    className="relative rounded-xl overflow-hidden cursor-pointer group aspect-[4/3]"
                    onClick={() => setPreviewImage(img.image_url)}
                  >
                    <img
                      src={img.image_url}
                      alt=""
                      className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-105"
                      loading="lazy"
                    />
                    <div className="absolute inset-0 bg-black/0 group-hover:bg-black/10 transition-colors" />
                    {img.photo_taken_at && (
                      <div className="absolute bottom-2 left-2 bg-black/60 text-white text-[10px] px-1.5 py-0.5 rounded">
                        📅 {img.photo_taken_at}
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </section>
          )}

          {/* Location info */}
          <section className="space-y-4">
            <div className="flex items-center gap-3">
              <div className="p-2.5 rounded-xl bg-muted">
                <Compass className="w-5 h-5 text-muted-foreground" />
              </div>
              <h2 className="text-xl font-bold text-foreground">
                {t("landmark.visitorInfo")}
              </h2>
            </div>
            <Card className="border-0 shadow-lg">
              <CardContent className="p-5 space-y-4">
                <div className="flex items-start gap-3">
                  <MapPin className="w-5 h-5 text-muted-foreground mt-0.5 shrink-0" />
                  <div>
                    <p className="font-medium text-sm text-foreground">
                      {t("landmark.location")}
                    </p>
                    <p className="text-muted-foreground text-sm mt-0.5">{restaurant.address}</p>
                  </div>
                </div>
                {restaurant.phone && (
                  <>
                    <Separator />
                    <div className="flex items-start gap-3">
                      <Phone className="w-5 h-5 text-muted-foreground mt-0.5 shrink-0" />
                      <div>
                        <p className="font-medium text-sm text-foreground">{t("landmark.phone", "联系电话")}</p>
                        <a href={`tel:${restaurant.phone}`} className="text-primary text-sm mt-0.5 hover:underline">{restaurant.phone}</a>
                      </div>
                    </div>
                  </>
                )}
                {restaurant.email && (
                  <>
                    <Separator />
                    <div className="flex items-start gap-3">
                      <Mail className="w-5 h-5 text-muted-foreground mt-0.5 shrink-0" />
                      <div>
                        <p className="font-medium text-sm text-foreground">{t("landmark.email", "电子邮箱")}</p>
                        <a href={`mailto:${restaurant.email}`} className="text-primary text-sm mt-0.5 hover:underline break-all">{restaurant.email}</a>
                      </div>
                    </div>
                  </>
                )}
                {restaurant.website_url && (
                  <>
                    <Separator />
                    <div className="flex items-start gap-3">
                      <Globe className="w-5 h-5 text-muted-foreground mt-0.5 shrink-0" />
                      <div>
                        <p className="font-medium text-sm text-foreground">{t("landmark.website", "官方网站")}</p>
                        <a href={restaurant.website_url} target="_blank" rel="noopener noreferrer" className="text-primary text-sm mt-0.5 hover:underline break-all">{restaurant.website_url.replace(/^https?:\/\//, '')}</a>
                      </div>
                    </div>
                  </>
                )}
                {restaurant.opening_hours && (
                  <>
                    <Separator />
                    <div className="flex items-start gap-3">
                      <CalendarClock className="w-5 h-5 text-muted-foreground mt-0.5 shrink-0" />
                      <div>
                        <p className="font-medium text-sm text-foreground">{t("landmark.openingHours", "办公/开放时间")}</p>
                        <div className="text-muted-foreground text-sm mt-0.5 space-y-0.5">
                          {typeof restaurant.opening_hours === 'object' && restaurant.opening_hours !== null
                            ? Object.entries(restaurant.opening_hours).map(([day, hours]) => (
                                <div key={day}><span className="font-medium">{day}:</span> {String(hours)}</div>
                              ))
                            : <span>{String(restaurant.opening_hours)}</span>
                          }
                        </div>
                      </div>
                    </div>
                  </>
                )}
                <Separator />
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <p className="text-xs text-muted-foreground uppercase tracking-wider font-medium">
                      {t("landmark.bestSeason")}
                    </p>
                    <p className="text-sm font-medium text-foreground mt-1">
                      {getLandmarkField("bestSeason") || t("landmark.yearRound")}
                    </p>
                  </div>
                  <div>
                    <p className="text-xs text-muted-foreground uppercase tracking-wider font-medium">
                      {t("landmark.duration")}
                    </p>
                    <p className="text-sm font-medium text-foreground mt-1">
                      {getLandmarkField("duration") || "-"}
                    </p>
                  </div>
                  <div>
                    <p className="text-xs text-muted-foreground uppercase tracking-wider font-medium">
                      {t("landmark.tickets")}
                    </p>
                    <p className="text-sm font-medium text-foreground mt-1">
                      {getLandmarkField("ticket") || t("landmark.free")}
                    </p>
                  </div>
                  <div>
                    <p className="text-xs text-muted-foreground uppercase tracking-wider font-medium">
                      {t("landmark.builtYear")}
                    </p>
                    <p className="text-sm font-medium text-foreground mt-1">
                      {getLandmarkField("builtYear") || "-"}
                    </p>
                  </div>
                </div>
                {getLandmarkField("transport") && (
                  <>
                    <Separator />
                    <div className="flex items-start gap-3">
                      <Bus className="w-5 h-5 text-muted-foreground mt-0.5 shrink-0" />
                      <div>
                        <p className="font-medium text-sm text-foreground">{t("landmark.transport")}</p>
                        <p className="text-muted-foreground text-sm mt-0.5 whitespace-pre-line">{getLandmarkField("transport")}</p>
                      </div>
                    </div>
                  </>
                )}
                {getLandmarkField("tips") && (
                  <>
                    <Separator />
                    <div className="flex items-start gap-3">
                      <Lightbulb className="w-5 h-5 text-muted-foreground mt-0.5 shrink-0" />
                      <div>
                        <p className="font-medium text-sm text-foreground">{t("landmark.tips")}</p>
                        <p className="text-muted-foreground text-sm mt-0.5 whitespace-pre-line">{getLandmarkField("tips")}</p>
                      </div>
                    </div>
                  </>
                )}
              </CardContent>
            </Card>

            {/* Map */}
            {lat && lng && (
              <div className="space-y-3">
                <div 
                  className="rounded-xl overflow-hidden border border-border shadow-lg relative" 
                  style={{ height: 240 }}
                  onWheel={(e) => {
                    if (!e.ctrlKey && !e.metaKey) {
                      setShowMapHint(true);
                      if (mapHintTimer.current) clearTimeout(mapHintTimer.current);
                      mapHintTimer.current = setTimeout(() => setShowMapHint(false), 2000);
                    }
                  }}
                  onTouchStart={(e) => {
                    if (e.touches.length < 2 && !mapInteractive) {
                      setShowMapHint(true);
                      if (mapHintTimer.current) clearTimeout(mapHintTimer.current);
                      mapHintTimer.current = setTimeout(() => setShowMapHint(false), 2000);
                    }
                  }}
                >
                  <div ref={mapContainer} className="w-full h-full" />
                  {/* Hint overlay */}
                  {showMapHint && (
                    <div className="absolute inset-0 z-20 flex items-center justify-center bg-foreground/40 pointer-events-none transition-opacity">
                      <span className="text-sm text-white bg-black/70 px-4 py-2 rounded-full">
                        {'ontouchstart' in window
                          ? t("map.scrollHintTouch", "使用双指移动地图")
                          : t("map.scrollHintDesktop", "使用 Ctrl + 滚轮缩放地图")}
                      </span>
                    </div>
                  )}
                </div>
                <a
                  href={`https://www.google.com/maps/dir/?api=1&destination=${lat},${lng}`}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="inline-flex items-center justify-center w-full h-10 px-4 rounded-md border border-input bg-background text-sm font-medium hover:bg-secondary hover:text-secondary-foreground transition-colors"
                >
                  <MapPin className="w-4 h-4 mr-1.5" />
                  {t("landmark.navigate", "导航")}
                </a>
              </div>
            )}
          </section>

          {/* Rating Section */}
          <Separator />
          <RestaurantRating restaurantId={restaurant.id} />

          {/* Comments Section */}
          <Separator />
          <Suspense fallback={
            <div className="flex items-center justify-center py-12">
              <Loader2Icon className="w-8 h-8 animate-spin text-primary" />
            </div>
          }>
            <RestaurantComments restaurantId={restaurant.id} />
          </Suspense>
        </div>
        <ImagePreviewModal
          isOpen={!!previewImage}
          onClose={() => setPreviewImage(null)}
          imageUrl={previewImage || ""}
        />
      </div>
      <LandmarkEditChoiceDialog
        open={showEditChoice}
        onOpenChange={setShowEditChoice}
        onChooseManual={() => setIsEditing(true)}
        onChooseAI={() => setShowAIEdit(true)}
      />
      <LandmarkAIEditPanel
        open={showAIEdit}
        onClose={() => setShowAIEdit(false)}
        restaurant={restaurant}
        onEditSuccess={onRefresh}
      />
      {/* Login Required Dialog */}
      <AlertDialog open={showLoginDialog} onOpenChange={setShowLoginDialog}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>{t("activities.loginRequired")}</AlertDialogTitle>
            <AlertDialogDescription>
              {t("activities.loginRequiredMessage")}
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>{t("common.cancel")}</AlertDialogCancel>
            <AlertDialogAction onClick={() => navigate("/auth")}>
              {t("activities.goToLogin")}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </PullToRefresh>
  );
};
