import { useTranslation } from "react-i18next";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Pencil, Bot } from "lucide-react";

interface LandmarkEditChoiceDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onChooseManual: () => void;
  onChooseAI: () => void;
}

const LandmarkEditChoiceDialog = ({
  open,
  onOpenChange,
  onChooseManual,
  onChooseAI,
}: LandmarkEditChoiceDialogProps) => {
  const { t } = useTranslation();

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-md">
        <DialogHeader>
          <DialogTitle>{t("landmark.edit.chooseMode")}</DialogTitle>
        </DialogHeader>
        <div className="grid grid-cols-2 gap-4 pt-2">
          <button
            onClick={() => {
              onOpenChange(false);
              onChooseManual();
            }}
            className="flex flex-col items-center gap-3 p-6 rounded-lg border-2 border-border hover:border-primary hover:bg-accent transition-all cursor-pointer group"
          >
            <div className="w-12 h-12 rounded-full bg-primary/10 flex items-center justify-center group-hover:bg-primary/20 transition-colors">
              <Pencil className="w-6 h-6 text-primary" />
            </div>
            <div className="text-center">
              <div className="font-medium text-sm">{t("landmark.edit.manualEdit")}</div>
              <div className="text-xs text-muted-foreground mt-1">
                {t("landmark.edit.manualEditDesc")}
              </div>
            </div>
          </button>

          <button
            onClick={() => {
              onOpenChange(false);
              onChooseAI();
            }}
            className="flex flex-col items-center gap-3 p-6 rounded-lg border-2 border-border hover:border-primary hover:bg-accent transition-all cursor-pointer group"
          >
            <div className="w-12 h-12 rounded-full bg-primary/10 flex items-center justify-center group-hover:bg-primary/20 transition-colors">
              <Bot className="w-6 h-6 text-primary" />
            </div>
            <div className="text-center">
              <div className="font-medium text-sm">{t("landmark.edit.aiEdit")}</div>
              <div className="text-xs text-muted-foreground mt-1">
                {t("landmark.edit.aiEditDesc")}
              </div>
            </div>
          </button>
        </div>
      </DialogContent>
    </Dialog>
  );
};

export default LandmarkEditChoiceDialog;
